def configure_kong_infrastructure(admin_url: str = "http://localhost:8001"):
    kong = KongAdminAPI(admin_url)
    
    print("Checking Kong status...")
    status = kong.get_status()
    print(f"Kong is running. Database: {status.get('database', {}).get('reachable', False)}")
    
    print("\n=== Creating Upstream ===")
    upstream = kong.create_upstream(
        name="backend-upstream",
        algorithm="round-robin",
        healthchecks={
            "active": {
                "healthy": {
                    "interval": 5,
                    "successes": 2
                },
                "unhealthy": {
                    "interval": 5,
                    "http_failures": 3
                }
            }
        }
    )
    print(f"Created upstream: {upstream['name']} (ID: {upstream['id']})")
    
    print("\n=== Adding Targets to Upstream ===")
    targets = [
        {"target": "backend1.example.com:8080", "weight": 100},
        {"target": "backend2.example.com:8080", "weight": 100},
        {"target": "backend3.example.com:8080", "weight": 50}
    ]
    
    for target_data in targets:
        target = kong.create_target(
            upstream_id=upstream['id'],
            target=target_data['target'],
            weight=target_data['weight']
        )
        print(f"Added target: {target['target']} (weight: {target['weight']})")
    
    print("\n=== Creating Service with Upstream ===")
    service = kong.create_service(
        name="api-service",
        host="backend-upstream",
        port=80,
        path="/api",
        protocol="http",
        retries=5,
        connect_timeout=60000,
        write_timeout=60000,
        read_timeout=60000,
        tags=["production", "api"]
    )
    print(f"Created service: {service['name']} (ID: {service['id']})")
    
    print("\n=== Creating Routes ===")
    route1 = kong.create_route(
        service_id=service['id'],
        name="api-route",
        protocols=["http", "https"],
        methods=["GET", "POST", "PUT", "DELETE"],
        paths=["/api"],
        strip_path=True,
        preserve_host=False,
        tags=["production"]
    )
    print(f"Created route: {route1['name']} (ID: {route1['id']})")
    
    route2 = kong.create_route(
        service_id=service['id'],
        name="api-v2-route",
        protocols=["https"],
        hosts=["api.example.com"],
        paths=["/v2"],
        strip_path=False,
        tags=["production", "v2"]
    )
    print(f"Created route: {route2['name']} (ID: {route2['id']})")
    
    print("\n=== Adding Plugins ===")
    rate_limit_plugin = kong.add_plugin(
        plugin_name="rate-limiting",
        service_id=service['id'],
        config={
            "minute": 100,
            "hour": 1000,
            "policy": "local"
        }
    )
    print(f"Added rate-limiting plugin (ID: {rate_limit_plugin['id']})")
    
    cors_plugin = kong.add_plugin(
        plugin_name="cors",
        service_id=service['id'],
        config={
            "origins": ["*"],
            "methods": ["GET", "POST", "PUT", "DELETE", "OPTIONS"],
            "headers": ["Accept", "Authorization", "Content-Type"],
            "exposed_headers": ["X-Auth-Token"],
            "credentials": True,
            "max_age": 3600
        }
    )
    print(f"Added CORS plugin (ID: {cors_plugin['id']})")
    
    request_transformer = kong.add_plugin(
        plugin_name="request-transformer",
        route_id=route1['id'],
        config={
            "add": {
                "headers": ["X-Service:api-service"]
            }
        }
    )
    print(f"Added request-transformer plugin (ID: {request_transformer['id']})")
    
    print("\n=== Creating Additional Service (Direct URL) ===")
    auth_service = kong.create_service(
        name="auth-service",
        url="http://auth.example.com:8000/authenticate",
        tags=["auth", "production"]
    )
    print(f"Created service: {auth_service['name']} (ID: {auth_service['id']})")
    
    auth_route = kong.create_route(
        service_id=auth_service['id'],
        name="auth-route",
        protocols=["https"],
        paths=["/auth"],
        methods=["POST"],
        tags=["auth"]
    )
    print(f"Created route: {auth_route['name']} (ID: {auth_route['id']})")
    
    print("\n=== Creating Consumer ===")
    consumer = kong.create_consumer(
        username="api-client",
        custom_id="client-001",
        tags=["external"]
    )
    print(f"Created consumer: {consumer['username']} (ID: {consumer['id']})")
    
    print("\n=== Configuration Summary ===")
    print(f"Services: {len(kong.list_services()['data'])}")
    print(f"Routes: {len(kong.list_routes()['data'])}")
    print(f"Upstreams: {len(kong.list_upstreams()['data'])}")
    print(f"Plugins: {len(kong.list_plugins()['data'])}")
    print(f"Consumers: {len(kong.list_consumers()['data'])}")
    
    return {
        "upstream": upstream,
        "service": service,
        "routes": [route1, route2],
        "auth_service": auth_service,
        "auth_route": auth_route,
        "consumer": consumer
    }


